import { Faction, FloorLevel, MonsterKind, RoomType, type ZoneFaction } from '../core/types';

export type RumorTopic =
  | 'samosbor'
  | 'rare_item'
  | 'faction'
  | 'room'
  | 'monster'
  | 'floor'
  | 'economy'
  | 'contract'
  | 'container'
  | 'player_action';

export type RumorReveal =
  | { kind: 'zone'; zoneId?: number; faction?: ZoneFaction; confidence: number }
  | { kind: 'room'; roomType?: RoomType; roomName?: string; confidence: number }
  | { kind: 'item'; itemId: string; confidence: number }
  | { kind: 'monster'; monsterKind?: MonsterKind; confidence: number }
  | { kind: 'floor'; floor: FloorLevel; confidence: number }
  | { kind: 'faction'; faction?: Faction; confidence: number }
  | { kind: 'danger'; level: number; confidence: number }
  | { kind: 'container'; name?: string; tag?: string; confidence: number }
